package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVParserTest {

    private CSVParser csvParser;
    private Lexer lexerMock;

    @BeforeEach
    public void setUp() throws Exception {
        // Create a CSVFormat mock or use null if format is not used in getCurrentLineNumber
        CSVFormat formatMock = mock(CSVFormat.class);

        // Instantiate CSVParser with a Reader and format
        csvParser = new CSVParser(new java.io.StringReader(""), formatMock);

        // Create a mock Lexer
        lexerMock = mock(Lexer.class);

        // Use reflection to set the private final field 'lexer' in csvParser instance
        Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(csvParser, lexerMock);
    }

    @Test
    public void testGetCurrentLineNumber() {
        // Arrange
        long expectedLineNumber = 42L;
        when(lexerMock.getCurrentLineNumber()).thenReturn(expectedLineNumber);

        // Act
        long actualLineNumber = csvParser.getCurrentLineNumber();

        // Assert
        assertEquals(expectedLineNumber, actualLineNumber);
    }
}
